sql:
SELECT c.*, cr.*
FROM customers c
INNER JOIN customer_retention cr ON c.customer_id = cr.customer_id
WHERE cr.retention_rate = (
    SELECT MAX(retention_rate) FROM customer_retention
);

SELECT email, phone_number
FROM customers
WHERE retirement_status = 1 AND gender = 0;

external_knowledge:
- longstanding customers refers to customers with a tenure of more than 24 months; 
- affluent customers refers to customers with an annual income above $60,000; 
- not retired refers to customers with a retirement status of 0, which indicates they are active.

sql:
SELECT c.customer_id, c.retirement_status, c.region, c.income
FROM customers c
WHERE c.retirement_status = 1 AND c.region = 5 AND c.income > 80000;

SELECT *
FROM user_activities
WHERE user_id = 1;

SELECT customer_id, SUM(number_of_purchases) AS total_purchases
FROM customer_retention
GROUP BY customer_id;
